const items = $input.all();
const companies = [];
const seen = new Set();

for (const item of items) {
  let html = '';
  if (typeof item.json === 'string') {
    html = item.json;
  } else if (item.json.data) {
    html = item.json.data;
  } else {
    html = JSON.stringify(item.json);
  }

  // Extract company names from job listings HTML
  // Look for company name patterns in Wellfound HTML
  const companyMatches = html.match(/\"startup_name\":\"([^\"]+)\"/g) || [];
  const nameMatches = html.match(/\"company_name\":\"([^\"]+)\"/g) || [];
  const allMatches = [...companyMatches, ...nameMatches];

  // Also try to extract from title/heading patterns
  const titleMatches = html.match(/<h2[^>]*>\s*([^<]{3,60})\s*<\/h2>/g) || [];

  for (const match of allMatches) {
    const name = match.replace(/.*:\"/, '').replace(/\".*/, '').trim();
    if (name && name.length > 1 && !seen.has(name)) {
      seen.add(name);
      companies.push({
        json: {
          Company: name,
          Website: 'Unknown',
          Careers_URL: 'Unknown',
          Country: 'Unknown',
          City: 'Unknown',
          Sector: 'Technology',
          Subsector: 'Data Engineering',
          Company_Stage: 'Unknown',
          Company_Scale: 'Unknown',
          Employer_Category: 'Remote-first',
          Remote: 'Yes',
          Visa_Sponsorship: 'Unknown',
          EOR: 'Unknown',
          Hiring_Geography: 'Global',
          Target_Roles: 'Data Engineer',
          Tech_Stack: 'Unknown',
          Region_Eligibility: 'Unknown',
          Portfolio_Theme_Match: 'Unknown',
          Language_Requirement: 'English',
          Hiring_Confidence: 'High',
          Reason_Match: 'Actively hiring Data Engineers remotely on Wellfound',
          Source: 'Wellfound Remote',
          Cold_Outreach_Candidate: 'Yes',
          Visa_Sponsor_Register: 'Unknown'
        }
      });
    }
  }
}

if (companies.length === 0) {
  return [{ json: { message: 'No companies parsed from Wellfound HTML', note: 'May require JS rendering or auth' } }];
}

return companies;
